mapper.sql:
WHERE 1 = 1

    AND R.ROLE_ID = #{roleId}


    AND R.ROLE_CODE LIKE CONCAT('%', #{roleCode}, '%')


    AND R.ROLE_NAME LIKE CONCAT('%', #{roleName}, '%')


    AND R.USE_YN = #{useYn}

mapper.select:
SELECT COUNT(*)
FROM ROLE R
WHERE R.ROLE_CODE = #{roleCode}

    AND R.ROLE_ID != #{excludeRoleId}

mapper.update:
UPDATE ROLE
SET ROLE_CODE = #{roleCode}
  , ROLE_NAME = #{roleName}
  , USE_YN    = #{useYn}
  , UPD_DT    = NOW()
WHERE ROLE_ID = #{roleId}
